import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box, Typography, Grid, Card, CardContent,
  Button, Skeleton, Chip, Stack,
} from '@mui/material';
import {
  LibraryBooks, CreditCard, NotificationsActive, ArrowForward,
  PlayArrow, Quiz,
} from '@mui/icons-material';
import { reviewAPI } from '../services/api';
import { useAuth } from '../contexts/AuthContext';

const StatCard = ({ icon, label, value, color, loading }) => (
  <Card sx={{ p: 0, overflow: 'hidden' }}>
    <CardContent sx={{ p: 2.5 }}>
      <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
        <Box>
          <Typography variant="caption" color="text.secondary" fontWeight={500} sx={{ textTransform: 'uppercase', letterSpacing: '0.05em', fontSize: '0.7rem' }}>
            {label}
          </Typography>
          {loading ? (
            <Skeleton variant="text" width={60} height={40} />
          ) : (
            <Typography variant="h3" fontWeight={700} sx={{ mt: 0.25, lineHeight: 1.1, letterSpacing: '-0.02em' }}>
              {value}
            </Typography>
          )}
        </Box>
        <Box sx={{ width: 36, height: 36, borderRadius: 2, bgcolor: `${color}.50`, display: 'flex', alignItems: 'center', justifyContent: 'center', mt: 0.25 }}>
          {React.cloneElement(icon, { sx: { fontSize: 20, color: `${color}.main` } })}
        </Box>
      </Box>
    </CardContent>
  </Card>
);

const DashboardPage = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    reviewAPI.getStats()
      .then(({ data }) => setStats(data.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const greeting = () => {
    const h = new Date().getHours();
    if (h < 12) return 'Good morning';
    if (h < 17) return 'Good afternoon';
    return 'Good evening';
  };

  return (
    <Box sx={{ py: 4, px: { xs: 2, md: 4 } }}>
      {/* Header */}
      <Box sx={{ mb: 4, display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', flexWrap: 'wrap', gap: 2 }}>
        <Box>
          <Typography variant="h4" fontWeight={700} gutterBottom>
            {greeting()}, {user?.name?.split(' ')[0]}.
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {stats?.cardsDueToday > 0
              ? `You have ${stats.cardsDueToday} card${stats.cardsDueToday === 1 ? '' : 's'} ready for review.`
              : "You're all caught up for today. Great work!"}
          </Typography>
        </Box>
        <Stack direction="row" spacing={1}>
          <Button
            variant="contained"
            startIcon={<PlayArrow />}
            onClick={() => navigate('/study-hub')}
            size="small"
          >
            Continue learning
          </Button>
          <Button
            variant="outlined"
            startIcon={<Quiz />}
            onClick={() => navigate('/study-hub')}
            size="small"
            sx={{ borderColor: 'divider', color: 'text.primary' }}
          >
            Quiz
          </Button>
        </Stack>
      </Box>

      {/* Stats */}
      <Grid container spacing={2} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={4}>
          <StatCard
            icon={<LibraryBooks />}
            label="Learning worlds"
            value={stats?.totalDecks ?? 0}
            color="primary"
            loading={loading}
          />
        </Grid>
        <Grid item xs={12} sm={4}>
          <StatCard
            icon={<CreditCard />}
            label="Cards learned"
            value={stats?.totalCards ?? 0}
            color="secondary"
            loading={loading}
          />
        </Grid>
        <Grid item xs={12} sm={4}>
          <StatCard
            icon={<NotificationsActive />}
            label="Due today"
            value={stats?.cardsDueToday ?? 0}
            color={stats?.cardsDueToday > 0 ? 'warning' : 'grey'}
            loading={loading}
          />
        </Grid>
      </Grid>

      {/* Due today callout */}
      {!loading && stats?.cardsDueToday > 0 && (
        <Card sx={{ mb: 4, bgcolor: '#EEF2FF', border: '1px solid #C7D2FE' }}>
          <CardContent sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', py: 2, flexWrap: 'wrap', gap: 2 }}>
            <Box>
              <Typography variant="subtitle1" fontWeight={600} color="primary.dark">
                Ready to review
              </Typography>
              <Typography variant="body2" color="primary.main">
                {stats.cardsDueToday} card{stats.cardsDueToday === 1 ? '' : 's'} are scheduled for today
              </Typography>
            </Box>
            <Button
              variant="contained"
              startIcon={<PlayArrow />}
              onClick={() => navigate('/study-hub')}
              size="small"
            >
              Start studying
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Recent decks */}
      <Box>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
          <Typography variant="h6" fontWeight={600}>Recently studied</Typography>
          <Button
            endIcon={<ArrowForward sx={{ fontSize: 16 }} />}
            size="small"
            onClick={() => navigate('/study-hub')}
            sx={{ color: 'primary.main', fontWeight: 500 }}
          >
            Learning hub
          </Button>
        </Box>

        {loading ? (
          <Grid container spacing={2}>
            {[1, 2, 3].map((i) => (
              <Grid item xs={12} sm={6} md={4} key={i}>
                <Card>
                  <CardContent>
                    <Skeleton variant="text" width="70%" height={24} />
                    <Skeleton variant="text" width="40%" height={20} sx={{ mt: 1 }} />
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        ) : stats?.recentDecks?.length > 0 ? (
          <Grid container spacing={2}>
            {stats.recentDecks.map((deck) => (
              <Grid item xs={12} sm={6} md={4} key={deck._id}>
                <Card
                  sx={{ cursor: 'pointer', '&:hover': { borderColor: 'primary.main' } }}
                  onClick={() => navigate(`/decks/${deck._id}`)}
                >
                  <CardContent sx={{ p: 2.5 }}>
                    <Typography variant="subtitle1" fontWeight={600} noWrap gutterBottom>
                      {deck.title}
                    </Typography>
                    <Stack direction="row" spacing={1} alignItems="center">
                      <Chip label={deck.category || 'General'} size="small" sx={{ fontSize: '0.7rem', height: 22 }} />
                      {deck.isPublic && (
                        <Chip label="Public" size="small" color="secondary" variant="outlined" sx={{ fontSize: '0.7rem', height: 22 }} />
                      )}
                    </Stack>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        ) : (
          <Card sx={{ bgcolor: 'grey.50', border: '1px dashed', borderColor: 'divider' }}>
            <CardContent sx={{ textAlign: 'center', py: 4 }}>
              <Typography variant="body2" color="text.secondary" gutterBottom>
                No study activity yet.
              </Typography>
              <Button variant="contained" size="small" onClick={() => navigate('/decks/new')} sx={{ mt: 1 }}>
                Add starter content
              </Button>
            </CardContent>
          </Card>
        )}
      </Box>
    </Box>
  );
};

export default DashboardPage;
